input.commands:
awk -F',' '
NR==1 {
    # Store header names
    for (i=1; i<=NF; i++) {
        headers[i] = $i
    }
    next
}
NR==2 {
    # Print opening bracket for array
    print "["
}
{
    # Print comma before each object except the first
    if (NR > 2) {
        print ","
    }

    # Build object
    printf "  {"
    for (i=1; i<=NF; i++) {
        if (i > 1) printf ", "
        printf "\"%s\": \"%s\"", headers[i], $i
    }
    printf "}"
}
END {
    # Print closing bracket
    print "\n]"
}
' /data/users.csv

