input.commands:
cat /doc/README.md | awk '
BEGIN { first_heading_found = 0; toc_inserted = 0 }
{
    # Check if this is a heading (starts with # or ##)
    if ($0 ~ /^#+ /) {
        # Extract heading level and text
        match($0, /^(#+) (.*)/, arr)
        level = length(arr[1])
        text = arr[2]

        # If this is the first heading and we haven't inserted TOC yet
        if (!first_heading_found) {
            first_heading_found = 1
            print $0
            next
        }

        # Store headings for TOC (only # and ##)
        if (level <= 2) {
            anchor = tolower(text)
            gsub(/ /, "-", anchor)
            headings[++count] = level "\t" text "\t" anchor
        }

        # If we haven't inserted TOC yet and we hit the second heading, insert it
        if (!toc_inserted && first_heading_found && level <= 2) {
            toc_inserted = 1
            print ""
            print "## Table of Contents"
            print ""
            for (i = 1; i <= count; i++) {
                split(headings[i], parts, "\t")
                hevel = parts[1]
                htext = parts[2]
                hanchor = parts[3]
                if (hevel == 1) {
                    print "- [" htext "](#" hanchor ")"
                } else if (hevel == 2) {
                    print "  - [" htext "](#" hanchor ")"
                }
            }
            print ""
        }

        print $0
    } else {
        print $0
    }
}
' > /tmp/processed.md

cat /tmp/processed.md

# Read the original file
original=$(cat /doc/README.md)

# Use basic awk to process
awk '
BEGIN {
    first_heading = 0
    toc_inserted = 0
    toc_items = ""
}
{
    if ($0 ~ /^# /) {
        print $0
        if (!first_heading) {
            first_heading = 1
        } else if (!toc_inserted) {
            toc_inserted = 1
            print ""
            print "## Table of Contents"
            print ""
            print toc_items
            print ""
        }
    } else if ($0 ~ /^## /) {
        if (!toc_inserted && first_heading) {
            toc_inserted = 1
            print ""
            print "## Table of Contents"
            print ""
            print toc_items
            print ""
        }
        print $0
    } else {
        print $0
    }

    # Collect heading for TOC
    if ($0 ~ /^# /) {
        text = substr($0, 3)
        anchor = tolower(text)
        gsub(/ /, "-", anchor)
        toc_items = toc_items "- [" text "](#" anchor ")\n"
    } else if ($0 ~ /^## /) {
        text = substr($0, 4)
        anchor = tolower(text)
        gsub(/ /, "-", anchor)
        toc_items = toc_items "  - [" text "](#" anchor ")\n"
    }
}
' /doc/README.md > /tmp/README_new.md

# Replace the file
cp /tmp/README_new.md /doc/README.md

echo "✓ Table of Contents generated and inserted successfully!"
echo ""
cat /doc/README.md

awk '
NR == 1 {
    heading_num = 0
}
/^# / || /^## / {
    level = ($0 ~ /^# /) ? 1 : 2
    text = ($0 ~ /^# /) ? substr($0, 3) : substr($0, 4)
    heading_levels[heading_num] = level
    heading_texts[heading_num] = text
    heading_num = heading_num + 1
}
{
    lines[NR] = $0
}
END {
    first_done = 0
    for (i = 1; i <= NR; i++) {
        print lines[i]
        if (lines[i] ~ /^# / && first_done == 0) {
            first_done = 1
            print ""
            print "## Table of Contents"
            print ""
            for (j = 0; j < heading_num; j++) {
                text = heading_texts[j]
                anchor = tolower(text)
                gsub(/ /, "-", anchor)
                if (heading_levels[j] == 1) {
                    print "- [" text "](#" anchor ")"
                } else {
                    print "  - [" text "](#" anchor ")"
                }
            }
            print ""
        }
    }
}
' /doc/README.md > /tmp/README_new.md

cp /tmp/README_new.md /doc/README.md

echo "✓ Table of Contents generated and inserted successfully!"
echo ""
cat /doc/README.md

